+        flex: 0 0 calc((100vw - (var(--spacing-md) * 2) - var(--spacing-lg) * 2) / 3);
+        min-width: 160px;
+        max-width: 200px;
+    }
+
+    /* Timeline: reducir padding lateral */
+    .timeline-item:nth-child(odd)  { padding-right: calc(50% + var(--spacing-md)); }
+    .timeline-item:nth-child(even) { padding-left:  calc(50% + var(--spacing-md)); }
+}
